import{c as s,Q as a,j as d,m as e}from "./chunks/framework.9Ry9ZBPK.js";const v=JSON.parse('{"title":"日常生活记录","description":"","frontmatter":{"title":"日常生活记录"},"headers":[],"relativePath":"moments/life/index.md","filePath":"moments/life/index.md","lastUpdated":1780385771000}'),t={name:"moments/life/index.md"};function n(m, i, l, r, g, o){return a(),d("div",null,[...i[0]||(i[0]=[e('<div class="moments-header"><div class="moments-header-content"><h1 class="moments-title">🌿 日常生活记录</h1><p class="moments-subtitle">生活不止代码 · 朋友圈记忆</p></div></div><div class="sort-controls"><button class="sort-btn active" data-order="desc">🔽 最新优先</button><button class="sort-btn" data-order="asc">🔼 最早优先</button></div><div class="timeline"><div class="moment-card"><span class="moment-date">24年12月13日</span><div class="moment-text">杰伦带我纯享 五公里[皱眉]<br><br>寒风中暖化我的心…<br><br>&quot;狼牙月 伊人憔悴 我举杯 饮尽了风雪 是谁打翻前世柜 惹尘埃是非 缘字诀 几番轮回&quot;</div><div class="moment-images"><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602142031983.jpg" alt="周杰伦歌曲" loading="lazy" decoding="async"></div><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602142240184.jpg" alt="五公里跑步" loading="lazy" decoding="async"></div></div></div><div class="moment-card"><span class="moment-date">25年1月3日</span><div class="moment-text">人生第一次万米，我做到了！<br><br>空寂的操场，一个人的背影，几首属于自己的歌，听风的心声，享受着我的自由！<br><br>这就是快乐，无与伦比的快乐！</div><div class="moment-images"><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602142428584.jpg" alt="万米跑步" loading="lazy" decoding="async"></div><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602142519634.jpg" alt="操场" loading="lazy" decoding="async"></div><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602142602736.jpg" alt="万米完成" loading="lazy" decoding="async"></div></div></div><div class="moment-card"><span class="moment-date">25年4月19日</span><div class="moment-text">望着夕阳，热忱的心蠢蠢欲动<br><br>换上装备，打开踩点音乐:METAMORPHOSIS，开启跑步之旅，有趣的故事在自由的凉风推动下开始…<br><br>二公里:偶遇恶犬，两脚对四足，优劣在我…&quot;调整跑步路线&quot;<br>五公里:侧腰罢工，扶腰暗叹 …<br>六公里:一切重回正轨…<br>七公里: 畅享呼吸，自信跨步…<br>恍惚间，低头一瞥…31分钟七公里…<br><br>八公里:耳机报数&quot;第八公里，耗时4分21&quot;<br>九公里:耳机报数&quot;耗时4分19&quot;<br>十公里:&quot;耳机报数:耗时三分52&quot;<br><br>十公里全程纯享版，一首歌沉浸式循环…恋恋不舍结束<br><br>夜幕笼罩，万籁俱静…吹着晚风，期待下一次相遇…</div><div class="moment-images"><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602143658394.jpg" alt="十公里跑步" loading="lazy" decoding="async"></div><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602143733430.jpg" alt="夜跑" loading="lazy" decoding="async"></div></div></div><div class="moment-card"><span class="moment-date">25年4月30日</span><div class="moment-text">OK呀，同款眼镜，我和偶像又近了一步……略略略 …[得意][得意]<br><br>该说不说，真人3D全景阴影加环音确实 …得劲…</div><div class="moment-images"><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602144143704.jpg" alt="同款眼镜" loading="lazy" decoding="async"></div><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602144227753.jpg" alt="眼镜特写" loading="lazy" decoding="async"></div><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602144246196.jpg" alt="偶像同款" loading="lazy" decoding="async"></div><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602144313372.jpg" alt="3D效果" loading="lazy" decoding="async"></div></div></div><div class="moment-card"><span class="moment-date">25年6月29日</span><div class="moment-text">全马?<br><br>可惜是两个轮蹬出来的[捂脸]<br><br>不过骑车确实比跑步…<br><br>嗯…忘本了…</div><div class="moment-images"><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602144641901.jpg" alt="骑行" loading="lazy" decoding="async"></div><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602144723358.jpg" alt="骑车" loading="lazy" decoding="async"></div><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602144748049.jpg" alt="骑行记录" loading="lazy" decoding="async"></div></div></div><div class="moment-card"><span class="moment-date">25年8月23日</span><div class="moment-text">&quot;我大抵是病了…&quot;<br><br>&quot;依旧笑得如此纯粹，哈哈&quot;<br><br>&quot;国漫巅峰这一块[破涕为笑]&quot;</div><div class="moment-images"><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602144922446.jpg" alt="国漫" loading="lazy" decoding="async"></div><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602144948867.jpg" alt="国漫巅峰" loading="lazy" decoding="async"></div><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602145007090.jpg" alt="动漫" loading="lazy" decoding="async"></div></div></div><div class="moment-card"><span class="moment-date">25年8月31日</span><div class="moment-text">&quot;十公里&quot;回归 但有些落魄了<br><br>跑了大概一暑假的五公里<br>零零散散掺杂数个七八公里…<br>确实掉了些速…<br><br>九月来了，清空颓废值 期待着<br>开学冲刺十公里 42分<br><br>&quot;熟悉的喘息声&quot;<br>&quot;熟悉的心跳&quot;<br>&quot;汗水再次浸透上衣&quot;<br>&quot;一切再次依旧…&quot;<br>&quot;还有那赤金的夕阳…&quot;<br><br>&quot;我等着 …一切都会越来越好&quot;</div><div class="moment-images"><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602145111071.jpg" alt="十公里回归" loading="lazy" decoding="async"></div><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602145136801.jpg" alt="夕阳" loading="lazy" decoding="async"></div></div></div><div class="moment-card"><span class="moment-date">25年9月13日</span><div class="moment-text">开学第一跑冲个记录<br><br>再洗个澡<br>看几集加菲猫<br>美美睡一觉<br><br>明天早起跑跑步，赏赏湖<br>再挑个早餐爽吃<br><br>—— 美滋滋——<br><br>小日子越来越有盼头了[呲牙]</div><div class="moment-images"><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602145338927.jpg" alt="开学第一跑" loading="lazy" decoding="async"></div><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602145357217.jpg" alt="跑步" loading="lazy" decoding="async"></div><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602145414533.jpg" alt="记录" loading="lazy" decoding="async"></div></div></div><div class="moment-card"><span class="moment-date">25年10月25日</span><div class="moment-text">十八岁第一次喝酒 怎么这么苦<br><br>也许喝完就不苦了<br>也许喝完就不难受了<br><br>……</div><div class="moment-images"><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602145529789.jpg" alt="第一次喝酒" loading="lazy" decoding="async"></div></div></div><div class="moment-card"><span class="moment-date">26年2月18日</span><div class="moment-text">跟白的相比，啤的简直就是小甜水……<br><br>酒桌文化吗？哈哈<br>再给我一点时间，我学得很快<br><br>万家灯火，车水马龙<br>趁年轻，总要闯出一番名堂<br><br>水浒传里店小二端上来的酒，剑来中养剑葫芦里藏的酒，究竟是什么滋味？<br>以后有机会，定要细品<br><br>人生漫漫，不过四个十八年<br>就像手中这杯摇晃的老窖，<br>不辣、不冲，那便丢了魂，枉活一世<br><br>笑听世间奇闻异事，一口烈酒下肚，什么都不顾，<br>那才叫痛快，那才叫豪迈<br><br>世间极乐，不过如此...</div></div><div class="moment-card"><span class="moment-date">26年2月26日</span><div class="moment-text">无地自容了又，给我的&quot;梦中情企&quot;丢人了，上了班估计连做梦都是件怪事[捂脸]</div><div class="moment-images"><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602145701861.jpg" alt="无地自容" loading="lazy" decoding="async"></div></div></div><div class="moment-card"><span class="moment-date">26年3月12日</span><div class="moment-text">活想明白了。。。<br><br>第一年学完四年的技术，成为合格的Java初级开发<br>第二年放开一切出去闯<br>第三年要是真被学历卡死了或者被AI一脚踹死了，就回来考研，上千公里都跑完了，有什么好怕的，破釜沉舟，才有意思<br><br>&quot;听着歌，键盘敲累了，就抿口小酒，发发呆，再哼几声小曲，多美啊&quot;<br><br>吐槽一句:&quot;高中不上进挖的坑，太难埋了，可惜回不去了。。下辈子喽&quot;</div></div><div class="moment-card"><span class="moment-date">26年3月30日</span><div class="moment-text">老男孩与春天<br><br>压不住的是嘴角...春风得意</div><div class="moment-images"><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602145849860.jpg" alt="老男孩" loading="lazy" decoding="async"></div><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602145915272.jpg" alt="春天" loading="lazy" decoding="async"></div></div></div><div class="moment-card"><span class="moment-date">26年4月16日</span><div class="moment-text">如何形容疲惫呢？<br><br>身子没撑住 无可奈何<br>之前堆了好久的心理大坝<br>就这样没了<br><br>也许还是不够坚强吧<br>还是菜<br>摸摸猫猫<br>但愿能找到一个平衡点吧<br>早一些习惯[啤酒]<br><br>自己选的嘛。。</div><div class="moment-images"><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602150026837.jpg" alt="疲惫" loading="lazy" decoding="async"></div></div></div><div class="moment-card"><span class="moment-date">26年4月21日</span><div class="moment-text">完美的剧本就是<br>成为幸福的乔恩<br>然后有一只属于自己的加菲猫<br>再摘一颗星星，送给心爱的丽莎<br>最后美美的睡一觉<br><br>全剧终[皱眉]<br><br>牛马平淡生活最后的期望</div><div class="moment-images"><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602150137657.jpg" alt="加菲猫" loading="lazy" decoding="async"></div><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602150157156.jpg" alt="星星" loading="lazy" decoding="async"></div></div></div><div class="moment-card"><span class="moment-date">26年4月30日</span><div class="moment-text">提上跑鞋是李洛克，<br>抱着酒瓶就是李逍遥了<br><br>转眼半月了。。<br><br>看习惯了万家灯火，<br>鲜血不再沸腾腾，但尚且温热<br><br>上一个三年输得一塌糊涂<br>这一个四年就竭尽全力赢一次吧<br><br>放弃了一切，那就别谈遗憾了</div><div class="moment-images"><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602150302170.jpg" alt="李洛克" loading="lazy" decoding="async"></div><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602150326072.jpg" alt="万家灯火" loading="lazy" decoding="async"></div></div></div><div class="moment-card"><span class="moment-date">26年5月8日</span><div class="moment-text">依旧阳光明媚<br>又是干劲十足的一天<br>核动力牛马[调皮]<br><br>周日周日 ～<br>心情雀跃<br>心花怒放<br>又又馋了。。</div><div class="moment-images"><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602150426227.jpg" alt="阳光明媚" loading="lazy" decoding="async"></div><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602150448483.jpg" alt="周日" loading="lazy" decoding="async"></div><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602150507781.jpg" alt="馋了" loading="lazy" decoding="async"></div></div></div><div class="moment-card"><span class="moment-date">26年5月12日</span><div class="moment-text">噩耗。。<br><br>已经失去了周六的晚上<br>再剥夺周日<br>小码农的心真要broken了<br><br>才周二，这手段太过残忍<br>人和代码都lose soul<br><br>幻想用手指敲碎键盘<br><br>仅此而已了。。<br>下周，下下周[捂脸]。。</div><div class="moment-images"><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602150605264.jpg" alt="噩耗" loading="lazy" decoding="async"></div></div></div><div class="moment-card"><span class="moment-date">26年5月19日</span><div class="moment-text">&quot;他花败尽，我如初，骄阳似火&quot;<br><br>叱咤风云 我任意闯万众仰望<br>叱咤风云 我绝不需往后看<br>翻天覆地 我定我写自我的法律<br>这凶悍闪烁眼光的野狼<br>天生我喜欢<br>傲慢做本性 忘形言行失敬<br>哪管你 万世巨星<br>这是率性 我任性 以天性<br><br>&quot;一个字 &#39;猛&#39;&quot;<br><br>&quot;我在，别怕&quot;</div><div class="moment-images"><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602150656435.jpg" alt="骄阳似火" loading="lazy" decoding="async"></div><div class="img-wrapper"><div class="img-skeleton"></div><img src="https://cdn.jsdelivr.net/gh/iuCoder99/blog_images@main/images/20260602150719208.jpg" alt="叱咤风云" loading="lazy" decoding="async"></div></div></div></div><div class="moments-lightbox" id="momentsLightbox"><button class="lightbox-close" aria-label="关闭">×</button><button class="lightbox-nav prev" aria-label="上一张">‹</button><img src="" alt="预览图片"><button class="lightbox-nav next" aria-label="下一张">›</button><div class="lightbox-counter"></div></div>',4)])])}const b=s(t,[["render",n]]);export{v as __pageData,b as default};
